# ── Ollama helper ────────────────────────────────────────────────────────────
def get_ollama_insights(r, score, razones):
    # Braces in f-strings must be doubled {{ }} to appear as literal { }
    prompt = f"""
Eres un analista de ventas experto en retención de clientes de bebidas.
Un modelo de ML predijo que el cliente tiene {score:.0%} de probabilidad de churn.

Datos del cliente:
- Caída de ventas corto plazo (ratio): {r['caida_ventas_corto_plazo']:.2f}
- Desaceleración de transacciones: {r['desaceleracion_transacciones']:.2f}
- Total cajas vendidas históricas: {r['total_cajas_vendidas']:.0f}
- Promedio cajas últimos 3 meses: {r['promedio_cajas_3m']:.1f}
- Promedio cajas histórico: {r['promedio_cajas_hist']:.1f}
- Número de coolers: {r['num_coolers']:.0f}
- Número de puertas: {r['num_doors']:.0f}
- Eficiencia cooler: {r['eficiencia_cooler']:.2f}
- Territorio: {r.get('territory_d', 'N/A')}
- Canal comercial: {r.get('comercial_subchannel_d', 'N/A')}
- Tamaño de cliente: {r.get('rtm_customer_size_d', 'N/A')}
- Señales detectadas: {', '.join(razones) if razones else 'Desgaste general'}

Responde ÚNICAMENTE con un objeto JSON válido con exactamente estas claves:
{{"resumen": "texto aquí", "causas": ["causa 1", "causa 2"], "acciones": ["acción 1", "acción 2"]}}
"""
    try:
        response = requests.post(
            "http://localhost:11434/api/generate",
            json={
                "model": OLLAMA_MODEL,
                "prompt": prompt,
                "stream": False,
                "format": "json"
            },
            timeout=60
        )
        response.raise_for_status()
        raw = response.json().get("response", "{}")
        result = json.loads(raw)
        # Validate expected keys exist
        for key in ("resumen", "causas", "acciones"):
            if key not in result:
                result[key] = [] if key != "resumen" else "Sin información disponible."
        return result
    except requests.exceptions.ConnectionError:
        raise ConnectionError(
            "No se pudo conectar con Ollama en http://localhost:11434. "
            f"Asegúrate de que Ollama está corriendo y el modelo '{OLLAMA_MODEL}' está descargado "
            f"(`ollama pull {OLLAMA_MODEL}`)."
        )
    except json.JSONDecodeError as e:
        raise ValueError(f"Ollama devolvió JSON inválido: {e}")

# ── Data loaders ──────────────────────────────────────────────────────────────
_BASE = Path(__file__).parent

@st.cache_data
def load_data():
    test    = pd.read_csv(_BASE / "data" / "sales_churn_test.csv")
    clients = pd.read_csv(_BASE / "data" / "Clientes.csv")
    coolers = pd.read_csv(_BASE / "data" / "Coolers.csv")
    return test, clients, coolers

@st.cache_data
def build_features(df_raw, df_clientes, df_coolers):
    df = df_raw.copy().sort_values(['customer_id', 'calmonth'])
    if 'target' in df.columns:
        df = df.drop(columns=['target'])

    last3 = df.groupby('customer_id').tail(3).groupby('customer_id').agg(
        promedio_transacciones_3m=('num_transacciones', 'mean'),
        promedio_cajas_3m=('uni_boxes_sold_m', 'mean')
    ).reset_index()

    hist = df.groupby('customer_id').agg(
        total_transacciones=('num_transacciones', 'sum'),
        total_cajas_vendidas=('uni_boxes_sold_m', 'sum'),
        promedio_transacciones_hist=('num_transacciones', 'mean'),
        promedio_cajas_hist=('uni_boxes_sold_m', 'mean'),
        max_cajas_un_mes=('uni_boxes_sold_m', 'max')
    ).reset_index()

    feats = pd.merge(hist, last3, on='customer_id', how='left')
    feats['caida_ventas_corto_plazo']     = feats['promedio_cajas_3m'] / (feats['promedio_cajas_hist'] + 0.1)
    feats['desaceleracion_transacciones'] = feats['promedio_transacciones_3m'] / (feats['promedio_transacciones_hist'] + 0.1)

    coolers_latest = df_coolers.sort_values('calmonth').groupby('customer_id').last().reset_index().drop(columns=['calmonth'])
    feats = pd.merge(feats, coolers_latest, on='customer_id', how='left')
    feats['num_coolers'] = feats['num_coolers'].fillna(0)
    feats['num_doors']   = feats['num_doors'].fillna(0)
    feats['eficiencia_cooler'] = feats['promedio_cajas_hist'] / (feats['num_doors'] + 0.1)

    df_c = df_clientes.copy()
    df_c['rtm_customer_size_d'] = df_c['rtm_customer_size_d'].fillna('DESCONOCIDO')
    feats = pd.merge(feats, df_c, on='customer_id', how='left')
    return feats

@st.cache_resource
def load_model():
    return lgb.Booster(model_file=str(_BASE / "modelo_churn.txt"))

