if filtro_nivel == "CRITICO (3 señales)":
    filtered_risk = filtered_risk[filtered_risk['score_negocio'] == 3]
elif filtro_nivel == "ALTO (2 señales)":
    filtered_risk = filtered_risk[filtered_risk['score_negocio'] == 2]

top_risk = filtered_risk.sort_values('score_negocio', ascending=False).head(15).reset_index(drop=True)

