# Exportar lista filtrada
export_cols = ['customer_id', 'territory_d', 'comercial_subchannel_d', 'score_negocio',
               'caida_ventas_corto_plazo', 'desaceleracion_transacciones',
               'promedio_cajas_3m', 'promedio_cajas_hist', 'num_doors']
