# ── Render enriched cards instead of plain dataframe ─────────────────────────
for _, row in top_risk.iterrows():
    signals = build_risk_signals(row)
    acciones = get_acciones(signals)
    n_signals = len(signals)
    badge_color = "#b91c1c" if n_signals == 3 else "#d97706" if n_signals == 2 else "#1d4ed8"
    badge_label = "CRÍTICO" if n_signals == 3 else "ALTO" if n_signals == 2 else "MODERADO"

    with st.expander(
        f"{badge_label}  ·  Cliente `{row['customer_id']}`  ·  {row.get('territory_d', 'Sin territorio')}  ·  {n_signals}/3 señales",
        expanded=(n_signals == 3)
    ):
        left, right = st.columns(2)

        with left:
            st.markdown("**Por qué está en riesgo**")
            for emoji, label, detail in signals:
                st.markdown(
                    f"<div style='background:#2d0035;border-left:3px solid #f472b6;"
                    f"padding:8px 12px;border-radius:6px;margin-bottom:8px;'>"
                    f"<b>{emoji} {label}</b><br>"
                    f"<span style='color:#f9a8d4;font-size:0.9rem'>{detail}</span>"
                    f"</div>",
                    unsafe_allow_html=True
                )
            # Quick stats
            st.markdown(
                f"<div style='color:#a78bfa;font-size:0.82rem;margin-top:6px'>"
                f"Prom. cajas 3M: <b>{row['promedio_cajas_3m']:.1f}</b> &nbsp;|&nbsp; "
                f"Histórico: <b>{row['promedio_cajas_hist']:.1f}</b> &nbsp;|&nbsp; "
                f"Puertas: <b>{row['num_doors']:.0f}</b>"
                f"</div>",
                unsafe_allow_html=True
            )

        with right:
            st.markdown("**Acciones preventivas**")
            for accion in acciones:
                st.markdown(
                    f"<div style='background:#1e3a1e;border-left:3px solid #4ade80;"
                    f"padding:8px 12px;border-radius:6px;margin-bottom:8px;"
                    f"color:#bbf7d0;font-size:0.9rem'>"
                    f"▶ {accion}"
                    f"</div>",
                    unsafe_allow_html=True
                )
            # Notas del administrador
            cid = str(row['customer_id'])
            nota_actual = st.session_state['notas_clientes'].get(cid, "")
            nueva_nota = st.text_area(
                "Notas del administrador",
                value=nota_actual,
                key=f"nota_{cid}",
                height=80,
                placeholder="Registra observaciones, visitas o acuerdos..."
            )
            if nueva_nota != nota_actual:
                st.session_state['notas_clientes'][cid] = nueva_nota